30: type LokiAPI struct {
31: 	client                    *http.Client
32: 	url                       string
33: 	log                       log.Logger
34: 	tracer                    tracing.Tracer
35: 	requestStructuredMetadata bool
36: }
37: 
38: type RawLokiResponse struct {
39: 	Body     []byte
40: 	Status   int
41: 	Encoding string
42: }
43: 
44: func newLokiAPI(client *http.Client, url string, log log.Logger, tracer tracing.Tracer, requestStructuredMetadata bool) *LokiAPI {
45: 	return &LokiAPI{client: client, url: url, log: log, tracer: tracer, requestStructuredMetadata: requestStructuredMetadata}
46: }
