48: func makeDataRequest(ctx context.Context, lokiDsUrl string, query lokiQuery, categorizeLabels bool) (*http.Request, error) {
49: 	qs := url.Values{}
50: 	qs.Set("query", query.Expr)
51: 
52: 	qs.Set("direction", string(query.Direction))
53: 
54: 	// MaxLines defaults to zero when not received,
55: 	// and Loki does not like limit=0, even when it is not needed
56: 	// (for example for metric queries), so we
57: 	// only send it when it's set
58: 	if query.MaxLines > 0 {
59: 		qs.Set("limit", fmt.Sprintf("%d", query.MaxLines))
60: 	}
61: 
62: 	lokiUrl, err := url.Parse(lokiDsUrl)
63: 	if err != nil {
64: 		return nil, err
65: 	}
66: 
67: 	switch query.QueryType {
68: 	case QueryTypeRange:
69: 		{
70: 			qs.Set("start", strconv.FormatInt(query.Start.UnixNano(), 10))
71: 			qs.Set("end", strconv.FormatInt(query.End.UnixNano(), 10))
72: 			// NOTE: technically for streams-producing queries `step`
73: 			// is ignored, so it would be nicer to not send it in such cases,
74: 			// but we cannot detect that situation, so we always send it.
75: 			// it should not break anything.
76: 			// NOTE2: we do this at millisecond precision for two reasons:
77: 			//  a. Loki cannot do steps with better precision anyway,
78: 			//     so the microsecond & nanosecond part can be ignored.
79: 			//  b. having it always be number+'ms' makes it more robust and
80: 			//     precise, as Loki does not support step with float number
81: 			//     and time-specifier, like "1.5s"
82: 			qs.Set("step", fmt.Sprintf("%dms", query.Step.Milliseconds()))
83: 			lokiUrl.Path = path.Join(lokiUrl.Path, "/loki/api/v1/query_range")
84: 		}
85: 	case QueryTypeInstant:
86: 		{
87: 			qs.Set("time", strconv.FormatInt(query.End.UnixNano(), 10))
88: 			lokiUrl.Path = path.Join(lokiUrl.Path, "/loki/api/v1/query")
89: 		}
90: 	default:
91: 		return nil, fmt.Errorf("invalid QueryType: %v", query.QueryType)
92: 	}
93: 
94: 	lokiUrl.RawQuery = qs.Encode()
95: 
96: 	req, err := http.NewRequestWithContext(ctx, "GET", lokiUrl.String(), nil)
97: 	if err != nil {
98: 		return nil, err
99: 	}
100: 
101: 	if query.SupportingQueryType != SupportingQueryNone {
102: 		value := getSupportingQueryHeaderValue(query.SupportingQueryType)
103: 		if value != "" {
104: 			req.Header.Set("X-Query-Tags", "Source="+value)
105: 		}
106: 	}
107: 
108: 	if categorizeLabels {
109: 		req.Header.Set("X-Loki-Response-Encoding-Flags", "categorize-labels")
110: 	}
111: 
112: 	setXScopeOrgIDHeader(req, ctx)
113: 
114: 	return req, nil
115: }
