167: func (api *LokiAPI) DataQuery(ctx context.Context, query lokiQuery, responseOpts ResponseOpts) (*backend.DataResponse, error) {
168: 	req, err := makeDataRequest(ctx, api.url, query, api.requestStructuredMetadata)
169: 	if err != nil {
170: 		return nil, err
171: 	}
172: 
173: 	queryAttrs := []any{"start", query.Start, "end", query.End, "step", query.Step, "query", query.Expr, "queryType", query.QueryType, "direction", query.Direction, "maxLines", query.MaxLines, "supportingQueryType", query.SupportingQueryType, "lokiHost", req.URL.Host, "lokiPath", req.URL.Path}
174: 	api.log.Debug("Sending query to loki", queryAttrs...)
175: 	start := time.Now()
176: 	resp, err := api.client.Do(req)
177: 	if err != nil {
178: 		status := "error"
179: 		if errors.Is(err, context.Canceled) {
180: 			status = "cancelled"
181: 		}
182: 		lp := []any{"error", err, "status", status, "duration", time.Since(start), "stage", stageDatabaseRequest}
183: 		lp = append(lp, queryAttrs...)
184: 		if resp != nil {
185: 			lp = append(lp, "statusCode", resp.StatusCode)
186: 		}
187: 		api.log.Error("Error received from Loki", lp...)
188: 		res := backend.DataResponse{
189: 			Error: err,
190: 		}
191: 		if errors.Is(err, syscall.ECONNREFUSED) {
192: 			res.ErrorSource = backend.ErrorSourceDownstream
193: 		}
194: 		return &res, nil
195: 	}
196: 
197: 	defer func() {
198: 		if err := resp.Body.Close(); err != nil {
199: 			api.log.Warn("Failed to close response body", "error", err)
200: 		}
201: 	}()
202: 
203: 	lp := []any{"duration", time.Since(start), "stage", stageDatabaseRequest, "statusCode", resp.StatusCode, "contentLength", resp.Header.Get("Content-Length")}
204: 	lp = append(lp, queryAttrs...)
205: 	if resp.StatusCode/100 != 2 {
206: 		err := readLokiError(resp.Body)
207: 		res := backend.DataResponse{
208: 			Error:       err,
209: 			ErrorSource: backend.ErrorSourceFromHTTPStatus(resp.StatusCode),
210: 		}
211: 		lp = append(lp, "status", "error", "error", err, "statusSource", res.ErrorSource)
212: 		api.log.Error("Error received from Loki", lp...)
213: 		return &res, nil
214: 	} else {
215: 		lp = append(lp, "status", "ok")
216: 		api.log.Info("Response received from loki", lp...)
217: 	}
218: 
219: 	start = time.Now()
220: 	_, span := api.tracer.Start(ctx, "datasource.loki.parseResponse", trace.WithAttributes(
221: 		attribute.Bool("metricDataplane", responseOpts.metricDataplane),
222: 	))
223: 	defer span.End()
224: 
225: 	iter := jsoniter.Parse(jsoniter.ConfigDefault, resp.Body, 1024)
226: 	res := converter.ReadPrometheusStyleResult(iter, converter.Options{Dataplane: responseOpts.metricDataplane})
227: 
228: 	if res.Error != nil {
229: 		span.RecordError(res.Error)
230: 		span.SetStatus(codes.Error, res.Error.Error())
231: 		instrumentation.UpdatePluginParsingResponseDurationSeconds(ctx, time.Since(start), "error")
232: 		api.log.Error("Error parsing response from loki", "error", res.Error, "metricDataplane", responseOpts.metricDataplane, "duration", time.Since(start), "stage", stageParseResponse)
233: 		return nil, res.Error
234: 	}
235: 	instrumentation.UpdatePluginParsingResponseDurationSeconds(ctx, time.Since(start), "ok")
236: 	api.log.Info("Response parsed from loki", "duration", time.Since(start), "metricDataplane", responseOpts.metricDataplane, "framesLength", len(res.Frames), "stage", stageParseResponse)
237: 
238: 	return &res, nil
239: }
