241: func makeRawRequest(ctx context.Context, lokiDsUrl string, resourcePath string) (*http.Request, error) {
242: 	lokiUrl, err := url.Parse(lokiDsUrl)
243: 	if err != nil {
244: 		return nil, err
245: 	}
246: 
247: 	resourceUrl, err := url.Parse(resourcePath)
248: 	if err != nil {
249: 		return nil, err
250: 	}
251: 
252: 	// we take the path and the query-string only
253: 	lokiUrl.RawQuery = resourceUrl.RawQuery
254: 	lokiUrl.Path = path.Join(lokiUrl.Path, resourceUrl.Path)
255: 
256: 	req, err := http.NewRequestWithContext(ctx, "GET", lokiUrl.String(), nil)
257: 
258: 	if err != nil {
259: 		return nil, err
260: 	}
261: 
262: 	setXScopeOrgIDHeader(req, ctx)
263: 
264: 	return req, nil
265: }
