267: func (api *LokiAPI) RawQuery(ctx context.Context, resourcePath string) (RawLokiResponse, error) {
268: 	api.log.Debug("Sending raw query to loki", "resourcePath", resourcePath)
269: 	req, err := makeRawRequest(ctx, api.url, resourcePath)
270: 	if err != nil {
271: 		api.log.Error("Failed to prepare request to loki", "error", err, "resourcePath", resourcePath)
272: 		return RawLokiResponse{}, err
273: 	}
274: 	start := time.Now()
275: 	resp, err := api.client.Do(req)
276: 	if err != nil {
277: 		status := "error"
278: 		if errors.Is(err, context.Canceled) {
279: 			status = "cancelled"
280: 		}
281: 		lp := []any{"error", err, "resourcePath", resourcePath, "status", status, "duration", time.Since(start), "stage", stageDatabaseRequest}
282: 		if resp != nil {
283: 			lp = append(lp, "statusCode", resp.StatusCode)
284: 		}
285: 		api.log.Error("Error received from Loki", lp...)
286: 		return RawLokiResponse{}, err
287: 	}
288: 
289: 	defer func() {
290: 		if err := resp.Body.Close(); err != nil {
291: 			api.log.Warn("Failed to close response body", "error", err)
292: 		}
293: 	}()
294: 
295: 	api.log.Info("Response received from loki", "status", "ok", "statusCode", resp.StatusCode, "contentLength", resp.Header.Get("Content-Length"), "duration", time.Since(start), "contentEncoding", resp.Header.Get("Content-Encoding"), "stage", stageDatabaseRequest)
296: 
297: 	// server errors are handled by the plugin-proxy to hide the error message
298: 	if resp.StatusCode/100 == 5 {
299: 		return RawLokiResponse{}, readLokiError(resp.Body)
300: 	}
301: 
302: 	body, err := io.ReadAll(resp.Body)
303: 	if err != nil {
304: 		api.log.Error("Error reading response body bytes", "error", err)
305: 		return RawLokiResponse{}, err
306: 	}
307: 
308: 	// client errors are passed as a json struct to the client
309: 	if resp.StatusCode/100 != 2 {
310: 		lokiResponseErr := lokiResponseError{Message: makeLokiError(body).Error()}
311: 		api.log.Warn("Non 200 HTTP status received from loki", "error", lokiResponseErr.Message, "statusCode", resp.StatusCode, "resourcePath", resourcePath)
312: 		traceID := tracing.TraceIDFromContext(ctx, false)
313: 		if traceID != "" {
314: 			lokiResponseErr.TraceID = traceID
315: 		}
316: 		body, err = json.Marshal(lokiResponseErr)
317: 		if err != nil {
318: 			return RawLokiResponse{}, err
319: 		}
320: 	}
321: 
322: 	rawLokiResponse := RawLokiResponse{
323: 		Body:     body,
324: 		Status:   resp.StatusCode,
325: 		Encoding: resp.Header.Get("Content-Encoding"),
326: 	}
327: 
328: 	return rawLokiResponse, nil
329: }
