331: func getSupportingQueryHeaderValue(supportingQueryType SupportingQueryType) string {
332: 	value := ""
333: 
334: 	// we need to map the SupportingQueryType to the actual header value. For
335: 	// legacy reasons we defined each value, such as "logsVolume" maps to the
336: 	// "logvolhist" header value to Loki. With #85123, even the value set in the
337: 	// frontend query can be passed as is to Loki.
338: 	switch supportingQueryType {
339: 	case SupportingQueryLogsVolume:
340: 		value = "logvolhist"
341: 	case SupportingQueryLogsSample:
342: 		value = "logsample"
343: 	case SupportingQueryDataSample:
344: 		value = "datasample"
345: 	case SupportingQueryInfiniteScroll:
346: 		value = "infinitescroll"
347: 	default:
348: 		value = string(supportingQueryType)
349: 	}
350: 
351: 	return value
352: }
