354: // setXScopeOrgIDHeader sets the `X-Scope-OrgID` header in the provided HTTP request based on the tenant ID retrieved from the context.
355: // `X-Scope-OrgID` is needed by the Loki system to work in multi-tenant mode.
356: // See https://github.com/grafana/loki/blob/main/docs/sources/operations/multi-tenancy.md
357: func setXScopeOrgIDHeader(req *http.Request, ctx context.Context) *http.Request {
358: 	logger := backend.NewLoggerWith("logger", "tsdb.loki")
359: 
360: 	md, ok := metadata.FromIncomingContext(ctx)
361: 	if !ok {
362: 		// Metadata are currently set and needed only locally for multi-tenancy, while on cloud
363: 		// this is set by our stack
364: 		logger.Debug("Metadata not present in context. Header not set")
365: 		return req
366: 	}
367: 
368: 	tenantids := md.Get("tenantid")
369: 	if len(tenantids) == 0 {
370: 		// We assume we are not using multi-tenant mode, which is fine
371: 		logger.Debug("Tenant ID not present. Header not set")
372: 	} else if len(tenantids) > 1 {
373: 		// Loki supports multiple tenant IDs, but we should receive them from different contexts
374: 		logger.Error(strconv.Itoa(len(tenantids)) + " tenant IDs found. Header not set")
375: 	} else {
376: 		req.Header.Add("X-Scope-OrgID", tenantids[0])
377: 		logger.Debug("Tenant ID " + tenantids[0] + " added to Loki request")
378: 	}
379: 	return req
380: }
