120: func callResource(ctx context.Context, req *backend.CallResourceRequest, sender backend.CallResourceResponseSender, dsInfo *datasourceInfo, plog log.Logger, tracer tracing.Tracer) error {
121: 	url := req.URL
122: 
123: 	lokiURL := fmt.Sprintf("/loki/api/v1/%s", url)
124: 
125: 	ctx, span := tracer.Start(ctx, "datasource.loki.CallResource", trace.WithAttributes(
126: 		attribute.String("url", lokiURL),
127: 	))
128: 	defer span.End()
129: 
130: 	api := newLokiAPI(dsInfo.HTTPClient, dsInfo.URL, plog, tracer, false)
131: 
132: 	rawLokiResponse, err := api.RawQuery(ctx, lokiURL)
133: 	if err != nil {
134: 		span.RecordError(err)
135: 		span.SetStatus(codes.Error, err.Error())
136: 		plog.Error("Failed resource call from loki", "err", err, "url", lokiURL)
137: 		return err
138: 	}
139: 	respHeaders := map[string][]string{
140: 		"content-type": {"application/json"},
141: 	}
142: 	if rawLokiResponse.Encoding != "" {
143: 		respHeaders["content-encoding"] = []string{rawLokiResponse.Encoding}
144: 	}
145: 	return sender.Send(&backend.CallResourceResponse{
146: 		Status:  rawLokiResponse.Status,
147: 		Headers: respHeaders,
148: 		Body:    rawLokiResponse.Body,
149: 	})
150: }
