191: func queryData(ctx context.Context, req *backend.QueryDataRequest, dsInfo *datasourceInfo, responseOpts ResponseOpts, tracer tracing.Tracer, plog log.Logger, runInParallel bool, requestStructuredMetadata bool) (*backend.QueryDataResponse, error) {
192: 	result := backend.NewQueryDataResponse()
193: 
194: 	api := newLokiAPI(dsInfo.HTTPClient, dsInfo.URL, plog, tracer, requestStructuredMetadata)
195: 
196: 	start := time.Now()
197: 	queries, err := parseQuery(req)
198: 	if err != nil {
199: 		plog.Error("Failed to prepare request to Loki", "error", err, "duration", time.Since(start), "queriesLength", len(queries), "stage", stagePrepareRequest)
200: 		return result, err
201: 	}
202: 
203: 	plog.Info("Prepared request to Loki", "duration", time.Since(start), "queriesLength", len(queries), "stage", stagePrepareRequest, "runInParallel", runInParallel)
204: 
205: 	ctx, span := tracer.Start(ctx, "datasource.loki.queryData.runQueries", trace.WithAttributes(
206: 		attribute.Bool("runInParallel", runInParallel),
207: 		attribute.Int("queriesLength", len(queries)),
208: 	))
209: 	if req.GetHTTPHeader("X-Query-Group-Id") != "" {
210: 		span.SetAttributes(attribute.String("query_group_id", req.GetHTTPHeader("X-Query-Group-Id")))
211: 	}
212: 	defer span.End()
213: 	start = time.Now()
214: 
215: 	// We are testing running of queries in parallel behind feature flag
216: 	if runInParallel {
217: 		resultLock := sync.Mutex{}
218: 		err = concurrency.ForEachJob(ctx, len(queries), 10, func(ctx context.Context, idx int) error {
219: 			query := queries[idx]
220: 			queryRes := executeQuery(ctx, query, req, runInParallel, api, responseOpts, tracer, plog)
221: 
222: 			resultLock.Lock()
223: 			defer resultLock.Unlock()
224: 			result.Responses[query.RefID] = queryRes
225: 			return nil // errors are saved per-query,always return nil
226: 		})
227: 	} else {
228: 		for _, query := range queries {
229: 			queryRes := executeQuery(ctx, query, req, runInParallel, api, responseOpts, tracer, plog)
230: 			result.Responses[query.RefID] = queryRes
231: 		}
232: 	}
233: 	plog.Debug("Executed queries", "duration", time.Since(start), "queriesLength", len(queries), "runInParallel", runInParallel)
234: 	return result, err
235: }
