237: func executeQuery(ctx context.Context, query *lokiQuery, req *backend.QueryDataRequest, runInParallel bool, api *LokiAPI, responseOpts ResponseOpts, tracer tracing.Tracer, plog log.Logger) backend.DataResponse {
238: 	ctx, span := tracer.Start(ctx, "datasource.loki.queryData.runQueries.runQuery", trace.WithAttributes(
239: 		attribute.Bool("runInParallel", runInParallel),
240: 		attribute.String("expr", query.Expr),
241: 		attribute.Int64("start_unixnano", query.Start.UnixNano()),
242: 		attribute.Int64("stop_unixnano", query.End.UnixNano()),
243: 	))
244: 	if req.GetHTTPHeader("X-Query-Group-Id") != "" {
245: 		span.SetAttributes(attribute.String("query_group_id", req.GetHTTPHeader("X-Query-Group-Id")))
246: 	}
247: 
248: 	defer span.End()
249: 
250: 	queryRes, err := runQuery(ctx, api, query, responseOpts, plog)
251: 	if queryRes == nil {
252: 		// we always want to return a backend.DataResponse object, even if we received just an error
253: 		queryRes = &backend.DataResponse{}
254: 	}
255: 
256: 	if err != nil {
257: 		span.RecordError(err)
258: 		span.SetStatus(codes.Error, err.Error())
259: 		queryRes.Error = err
260: 	}
261: 
262: 	return *queryRes
263: }
