266: func runQuery(ctx context.Context, api *LokiAPI, query *lokiQuery, responseOpts ResponseOpts, plog log.Logger) (*backend.DataResponse, error) {
267: 	res, err := api.DataQuery(ctx, *query, responseOpts)
268: 	if err != nil {
269: 		plog.Error("Error querying loki", "error", err)
270: 		return res, err
271: 	}
272: 
273: 	for _, frame := range res.Frames {
274: 		err = adjustFrame(frame, query, !responseOpts.metricDataplane, responseOpts.logsDataplane)
275: 
276: 		if err != nil {
277: 			plog.Error("Error adjusting frame", "error", err)
278: 			return res, err
279: 		}
280: 	}
281: 
282: 	return res, nil
283: }
